// // This module selects between two 16-bit inputs based on a 1-bit control signal. When sel is 1, the output is A; when sel is 0, the output is B.
module data_selector(  
    input [15:0] A,  
    input [15:0] B,  
    input sel,  
    output reg [15:0] Y  
);  
    always @(*) begin  
        if (sel == 0)  
            Y = A;  
        else  
            Y = B;  
    end  
endmodule
